Add 'export const metadata: Metadata' to all 46 pages. For dynamic pages in /e/[slug]/*, implement generateMetadata() functions. Example:

export async function generateMetadata({ params }: { params: { slug: string } }): Promise<Metadata> {
  const event = await fetchEventData(params.slug);
  return {
    title: event.name,
    description: event.description,
    alternates: { canonical: absoluteUrl(`/e/${params.slug}/`) },
  };
}

Convert static sitemap to dynamic generation using Next.js sitemap() function:

import { MetadataRoute } from 'next';

export default function sitemap(): MetadataRoute.Sitemap {
  const basePages = [{ url: 'https://cordivent.com/', changeFrequency: 'daily', priority: 1.0 }, ...];
  const dynamicEvents = events.map(e => ({ url: `https://cordivent.com/e/${e.slug}/`, changeFrequency: 'weekly', priority: 0.8 }));
  return [...basePages, ...dynamicEvents];
}

